if (auto *FCmp1 = dyn_cast<FCmpInst>(TrueVal)) {
  if (isFalse(FalseVal) && FCmp0->getPredicate() == CmpInst::FCMP_ORD) {
    Value *X = FCmp0->getOperand(0);
    Value *Y = FCmp0->getOperand(1);
    // Only if the first fcmp is comparing with a non-nan value.
    if (isa<Constant>(Y) && !cast<Constant>(Y)->isNaN()) {
      // The second fcmp must be on fabs(X).
      if (match(FCmp1->getOperand(0), m_Intrinsic<Intrinsic::fabs>(m_Specific(X)))) {
        // The second fcmp must be against infinity.
        const APFloat *K;
        if (match(FCmp1->getOperand(1), m_APFloat(K)) && K->isInfinity()) {
          // fcmp uge fabs(x), +inf  -> x is inf
          // fcmp oeq fabs(x), +inf  -> x is inf
          if (FCmp1->getPredicate() == CmpInst::FCMP_UGE ||
              FCmp1->getPredicate() == CmpInst::FCMP_OEQ) {
            // The transform is only valid if the fabs does not have nnan.
            // If it has nnan, a SNaN input to fabs will result in a poison,
            // which will propagate through the fcmp, making the result poison.
            // The original code would return false in this case because the
            // 'fcmp ord' would be false.
            if (auto *Fabs = dyn_cast<CallInst>(FCmp1->getOperand(0)))
              if (Fabs->hasNoNaNs())
                return nullptr;

            return Builder.CreateFCmpOEQ(FCmp1->getOperand(0),
                                         FCmp1->getOperand(1));
          }
```
